// Object to hold registered components
const components: { [key: string]: any } = {};

/**
 * Register a component.
 * @param name - Name of the component.
 * @param component - The component itself.
 */
function registerComponent(name: string, component: any): void {
    if (components[name]) {
        console.warn(`Component with the name "${name}" is already registered.`);
        return;
    }
    components[name] = component;
}

/**
 * Get a registered component by name.
 * @param name - Name of the component.
 * @returns The component if found, or undefined.
 */
function getComponent(name: string): any | undefined {
    return components[name];
}

/**
 * Get all registered components.
 * @returns An object mapping component names to components.
 */
function getAllComponents(): { [key: string]: any } {
    return { ...components }; // Return a shallow copy to prevent external manipulation
}

export {
    registerComponent,
    getComponent,
    getAllComponents
};
